import json
NODE_POSITIONS = {"Police_HQ":(90,55),"Traffic_Control_Center":(750,55),"North_Station":(440,95),"River_Bridge":(260,155),"Stadium":(90,230),"Airport_Road":(90,370),"Central_Junction":(440,255),"East_Market":(310,295),"West_Terminal":(570,295),"Fire_Station":(720,215),"South_Residential":(310,390),"City_Hospital":(210,435),"Industrial_Zone":(660,390)}
NODE_COLORS = {"Police_HQ":"#4488ff","Traffic_Control_Center":"#888888","North_Station":"#44aaff","River_Bridge":"#44dddd","Stadium":"#aa44ff","Airport_Road":"#4466ff","Central_Junction":"#ffaa00","East_Market":"#44cc44","West_Terminal":"#888888","Fire_Station":"#ff4444","South_Residential":"#88cc44","City_Hospital":"#ff2255","Industrial_Zone":"#cc4400"}
EDGES = [("Police_HQ","Traffic_Control_Center"),("Police_HQ","River_Bridge"),("Traffic_Control_Center","North_Station"),("River_Bridge","North_Station"),("River_Bridge","Stadium"),("North_Station","Central_Junction"),("Stadium","East_Market"),("Stadium","Airport_Road"),("Airport_Road","South_Residential"),("Central_Junction","East_Market"),("Central_Junction","West_Terminal"),("Central_Junction","South_Residential"),("East_Market","City_Hospital"),("West_Terminal","Fire_Station"),("West_Terminal","Industrial_Zone"),("South_Residential","City_Hospital")]
def generate_graph_html(route=None,is_emergency=False,vehicle_type="civilian"):
    route=route or []
    RC="#ff2255" if is_emergency else "#bf00ff"
    VE={"ambulance":"🚑","police":"🚓","fire_truck":"🚒","civilian":"🚗"}.get(vehicle_type.lower(),"🚗")
    return f"""<!DOCTYPE html><html><head><meta charset="utf-8"><style>*{{margin:0;padding:0;box-sizing:border-box}}body{{background:#0a0010;font-family:'Courier New',monospace;display:flex;flex-direction:column;align-items:center;padding:6px;width:100%}}canvas{{border:1.5px solid #3a005a;border-radius:10px;background:#0d001a;box-shadow:0 0 25px #bf00ff33;width:100%;height:auto}}#st{{margin-top:5px;color:#00ffaa;font-size:0.75em;font-weight:bold;letter-spacing:0.08em;text-align:center}}#leg{{display:flex;gap:10px;margin-top:3px;justify-content:center;flex-wrap:wrap}}.lg{{display:flex;align-items:center;gap:3px;color:#aaa;font-size:0.7em}}.dt{{width:7px;height:7px;border-radius:50%}}</style></head><body><canvas id="c" width="860" height="500"></canvas><div id="st">City map ready — submit a request to see live routing.</div><div id="leg"><div class="lg"><div class="dt" style="background:#00ffaa"></div>Start</div><div class="lg"><div class="dt" style="background:#ff2255"></div>Destination</div><div class="lg"><div class="dt" style="background:{RC}"></div>Route</div><div class="lg"><div class="dt" style="background:#ffaa00"></div>Junction</div></div><script>const cv=document.getElementById('c'),ctx=cv.getContext('2d'),st=document.getElementById('st');const N={json.dumps(NODE_POSITIONS)},E={json.dumps(EDGES)},C={json.dumps(NODE_COLORS)},R={json.dumps(route)};const RC="{RC}",VE="{VE}";const RE=new Set();for(let i=0;i<R.length-1;i++){{RE.add(R[i]+'|'+R[i+1]);RE.add(R[i+1]+'|'+R[i]);}}function glow(x1,y1,x2,y2,col,w,b){{ctx.save();ctx.shadowColor=col;ctx.shadowBlur=b;ctx.strokeStyle=col;ctx.lineWidth=w;ctx.beginPath();ctx.moveTo(x1,y1);ctx.lineTo(x2,y2);ctx.stroke();ctx.restore();}}function drawAll(vx,vy){{ctx.clearRect(0,0,cv.width,cv.height);ctx.fillStyle='#ffffff06';for(let gx=30;gx<860;gx+=45)for(let gy=30;gy<500;gy+=45){{ctx.beginPath();ctx.arc(gx,gy,1,0,Math.PI*2);ctx.fill();}}E.forEach(([a,b])=>{{const[x1,y1]=N[a],[x2,y2]=N[b];if(RE.has(a+'|'+b)){{glow(x1,y1,x2,y2,'#ffffff10',10,0);glow(x1,y1,x2,y2,RC,4,18);}}else glow(x1,y1,x2,y2,'#2a0055',1.5,0);}});const s=R[0],e=R[R.length-1];Object.entries(N).forEach(([nm,[x,y]])=>{{const iS=nm===s&&R.length>0,iE=nm===e&&R.length>0,iR=R.includes(nm);const bc=C[nm]||'#bf00ff';const r=iR?13:9;if(iR){{ctx.save();const g=ctx.createRadialGradient(x,y,r,x,y,r+14);g.addColorStop(0,iE?'#ff225544':iS?'#00ffaa44':RC+'33');g.addColorStop(1,'transparent');ctx.fillStyle=g;ctx.beginPath();ctx.arc(x,y,r+14,0,Math.PI*2);ctx.fill();ctx.restore();}}ctx.save();ctx.shadowColor=iS?'#00ffaa':iE?'#ff2255':iR?RC:bc;ctx.shadowBlur=iR?18:6;ctx.beginPath();ctx.arc(x,y,r,0,Math.PI*2);ctx.fillStyle=iS?'#00ffaa':iE?'#ff2255':iR?RC:bc+'aa';ctx.fill();ctx.strokeStyle=iR?'#ffffff':bc;ctx.lineWidth=iR?2:1;ctx.stroke();ctx.restore();const lb=nm.replace(/_/g,' ');ctx.font=(iR?'bold ':'')+' 9px Courier New';const tw=ctx.measureText(lb).width;ctx.fillStyle='#0a001099';ctx.fillRect(x-tw/2-2,y+r+3,tw+4,12);ctx.fillStyle=iR?'#ffffff':'#999';ctx.fillText(lb,x-tw/2,y+r+13);}});if(vx!==null){{ctx.save();ctx.beginPath();ctx.arc(vx,vy,16,0,Math.PI*2);ctx.fillStyle='#ffffff22';ctx.fill();ctx.shadowColor='#ffffff';ctx.shadowBlur=14;ctx.font='18px serif';ctx.textAlign='center';ctx.textBaseline='middle';ctx.fillText(VE,vx,vy);ctx.restore();}}}}function animate(){{if(!R||R.length<2){{drawAll(null,null);return;}}let seg=0,step=0;const STEPS=55;st.textContent='DISPATCHED — en route...';function tick(){{if(seg>=R.length-1){{const[ex,ey]=N[R[R.length-1]];drawAll(ex,ey);st.textContent='ARRIVED: '+R[R.length-1].replace(/_/g,' ');return;}}const[x1,y1]=N[R[seg]],[x2,y2]=N[R[seg+1]];const t=step/STEPS,et=t<0.5?2*t*t:-1+(4-2*t)*t;drawAll(x1+(x2-x1)*et,y1+(y2-y1)*et);st.textContent='Moving: '+R[seg].replace(/_/g,' ')+' to '+R[seg+1].replace(/_/g,' ');step++;if(step>STEPS){{step=0;seg++;}}setTimeout(tick,28);}}setTimeout(tick,400);}}drawAll(null,null);if(R.length>=2)animate();</script></body></html>"""
